using UnityEngine;
using FL.Gameplay.Modules.BigWorld;
using System.Reflection;
public class Script
{
    public static object Main()
    {
        var controllers = Object.FindObjectsOfType<BigWorldNpcController>();
        var sb = new System.Text.StringBuilder();
        sb.AppendLine("3s later - NPC count: " + controllers.Length);
        for (int i = 0; i < System.Math.Min(controllers.Length, 3); i++)
        {
            var c = controllers[i];
            if (c.TransformComp == null) continue;
            var field = typeof(FL.Gameplay.Modules.BigWorld.BigWorldNpcTransformComp).GetField("_snapshotQueue", BindingFlags.NonPublic | BindingFlags.Instance);
            var queue = field?.GetValue(c.TransformComp);
            var queueType = queue?.GetType();
            int count = (int)(queueType?.GetProperty("SnapshotCount")?.GetValue(queue) ?? -1);
            var pos = queueType?.GetProperty("Position")?.GetValue(queue);
            var transPos = c.GetTransform()?.position ?? Vector3.zero;
            sb.AppendLine("NPC["+i+"] entityId=" + c.NetId + " snapshotCount=" + count + " queuePos=" + pos + " transPos=" + transPos.ToString("F2") + " speed=" + c.MoveComp.CurrentSpeed.ToString("F3"));
        }
        return sb.ToString();
    }
}
